// Commenta queste righe per attivare/disattivare i componenti
#define SYNTH
#define WAVE

// Converte ottava e tono in frequenza Hz
float tone(float octave, float pitch) {
    float baseFreq = 264.0;
    baseFreq *= pow(2.0, octave);
    baseFreq *= pow(1.1041, pitch);
    return baseFreq;
}

// -------------------------------------------------------------------------
// GENERATORI DI RUMORE (Noise)
// -------------------------------------------------------------------------

float hash(float p) {
    float h = p * 127.1;
    return fract(sin(h) * 43758.5453123);
}

float perlinNoise(in float x) {
    float lower = floor(x);
    float upper = lower + 1.0;
    float lowerV = hash(lower);
    float upperV = hash(upper);
    return smoothstep(lower, upper, x) * (upperV - lowerV) + lowerV;
}

#define ITERATIONS 8
#define MOD3_WAVE vec3(443.8975, 397.2973, 491.1871)

vec2 hash22(in vec2 p) {
    vec3 p3 = fract(vec3(p.xyx) * MOD3_WAVE);
    p3 += dot(p3.zxy, p3.yxz + 19.19);
    return fract(vec2(p3.x * p3.y, p3.z * p3.x));
}

vec2 noise(in float time) {
    vec2 audio = vec2(0.0);
    for (int t = 0; t < ITERATIONS; t++) {
        float v = float(t) * 3.21239;
        audio += hash22(vec2(time + v, time * 1.423 + v)) * 2.0 - 1.0;
    }
    audio /= float(ITERATIONS);
    return audio;
}

// -------------------------------------------------------------------------
// SUONO DELLE ONDE
// -------------------------------------------------------------------------

#define SAMPLES 41
vec2 getWaveSound(in float time) {
    // Usiamo u_sampleRate passata dal tuo synthesizer.cpp
    float period = 1.0 / u_sampleRate;
    float t_snapped = floor(time / period) * period;
    float totAmpl = 0.0;
    vec2 audio = vec2(0);

    for (int i = 0; i < SAMPLES; i++) {
        float index = float(i - SAMPLES / 2);
        float currStepF = period * index;
        vec2 curr = noise(t_snapped + currStepF);
        index /= 2.0; 
        index *= index;
        float ampl = 1.0 - index;
        totAmpl += ampl;
        audio += curr * ampl;
    }
    return audio / totAmpl;
}

// -------------------------------------------------------------------------
// SINTETIZZATORE MELODICO
// -------------------------------------------------------------------------

#define SYNTH_HARMONICS 3
float getSynthBase(in float time, in float freq, in float frac) {
    float x = fract(time * freq);
    float value = 0.0;
    if (x < 0.078) {
        value = 0.692 - smoothstep(0.0, 0.078, x) * 0.588;
    } else if (x < 0.346) {
        value = smoothstep(0.078, 0.346, x) * 0.666 + 0.105; 
    } else if (x < 0.986) {
        value = 0.771 - smoothstep(0.346, 0.986, x) * 0.351;
    } else {
        value = smoothstep(0.986, 1.0, x) * 0.272 + 0.420;
    }

    value *= 2.7;
    float totAmpl = 2.7;

    float mult = time * 2.0 * PI * freq;
    for (int i = 0 ; i < SYNTH_HARMONICS ; i++) {
        float fact = 1.0 / pow(2.0, float(i));
        float harm = sin(mult * fact);
        float ampl = (cos(frac * 2.0 * PI) * 3.0 + 4.0) * (1.0 - fact) + 3.0;
        value += harm * ampl;
        totAmpl += ampl;
    }

    return value / totAmpl;
}

#define TEMPO 7.0

float getTone(in float time) {
    float timei = floor((time + TEMPO) / TEMPO);
    return floor((sin(timei * 3.95216) * 0.5 + 0.5) * 4.0);
}

#define PART_LENGTH 4.0
#define PART_COUNT 3.0
#define TOT_PART (PART_LENGTH * PART_COUNT)

vec2 getSynth(in float time) {
    float part = mod(floor(time / TEMPO / PART_LENGTH), PART_COUNT);
    if (mod(time, TEMPO * TOT_PART) > TEMPO * 7.0) return vec2(0);

    float currentTone = getTone(time);
    float frac = mod(time, TEMPO);
    float freq = tone(-2.0 + part, currentTone);
    float ampl = smoothstep(0.0, 2.0, frac) * (1.0 - smoothstep(TEMPO - 2.0, TEMPO, frac));
    float synthBase = ampl * getSynthBase(time, freq, mod(time, TEMPO) / TEMPO);

    float pan = smoothstep(0.0, TEMPO, frac); 
    if (mod(floor(time / TEMPO), 2.0) < 1.0) pan = 1.0 - pan;
    return vec2((1.0 - pan) * synthBase, pan * synthBase);
}

// -------------------------------------------------------------------------
// MAIN SOUND
// -------------------------------------------------------------------------

vec2 mainSound(int samp, float time) {
    vec2 result = vec2(0);

    #ifdef SYNTH
    result += smoothstep(0.0, 2.0, time) * getSynth(time);
    #endif

    #ifdef WAVE
    float waveAmpl = sin(time * 0.353) * 0.12 + 0.24;
    float perlinAmpl = 1.0 - perlinNoise(time * 1.2146) * 0.5;
    result += smoothstep(0.0, 12.0, time) * getWaveSound(time) * waveAmpl * perlinAmpl;
    #endif

    // VOLUME FINALE: Aumentato a 0.8 per maggiore impatto
    return result * 0.8; 
}
// SOUND_END
//SOUND_END

// --- PARAMETRI ---
float scale = 50.0; // Densità degli anelli (più alto = più cerchi)
vec2 center = vec2(0.5, 0.5); // Centro dei cerchi (0.5, 0.5 è il centro della texture)

// --- LOGICA ---
// 1. Calcola la distanza del pixel corrente (u, v) dal centro
float dist = distance(vec2(u, v), center);

// 2. Crea l'onda sinusoidale basata sulla distanza
// Moltiplichiamo per 'scale' per aumentare la frequenza
float val = sin(dist * scale);

// 3. Mappiamo il risultato da -1..1 a 0..1 per il mix
float t = (val + 1.0) * 0.5;

// 4. Mix finale
return mix(u_col1, u_col2, t);
